#include <stdio.h>
#include <stdlib.h>
#define MOD 109

long long fib[1000000];

long long calculateFib(long long n) {
    if (n < 2) return n;
    if (fib[n] != 0) return fib[n];
    fib[n] = (calculateFib(n-1) + calculateFib(n-2)) % MOD;
    return fib[n];
}

int main() {
    int N;
    scanf("%d", &N);
    long long Si[N], Ai[N], Li[N], Ui[N];
    for (int i = 0; i < N; i++) {
        scanf("%lld %lld %lld %lld", &Si[i], &Ai[i], &Li[i], &Ui[i]);
    }
    for (int i = 0; i < N; i++) {
        long long strength = 0;
        for (int mask = 0; mask < (1 << N); mask++) {
            long long sum = 0;
            for (int j = 0; j < N; j++) {
                if ((mask & (1 << j)) && j != i && Ai[i] >= Li[j] && Ai[i] <= Ui[j]) {
                    sum += Si[j];
                }
            }
            if (sum > 0) {
                strength = (strength + calculateFib(sum + 1)) % (MOD + 3);
            }
        }
        printf("%lld ", strength);
    }
    return 0;
}

