#include <iostream>
#include <vector>
#define MOD 109

long long calculateFib(long long n) {
    if (n < 2) return n;
    long long a = 0, b = 1, result = 0;
    for (long long i = 2; i <= n; i++) {
        result = (a + b) % MOD;
        a = b;
        b = result;
    }
    return result;
}

