import java.util.Scanner;

public class Main {
    static final long MOD = 109;
    static long[] fib = new long[1000000];

    public static long calculateFib(long n) {
        if (n < 2) return n;
        if (fib[(int)n] != 0) return fib[(int)n];
        fib[(int)n] = (calculateFib(n-1) + calculateFib(n-2)) % MOD;
        return fib[(int)n];
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        long[] Si = new long[N], Ai = new long[N], Li = new long[N], Ui = new long[N];
        for (int i = 0; i < N; i++) {
            Si[i] = scanner.nextLong();
            Ai[i] = scanner.nextLong();
            Li[i] = scanner.nextLong();
            Ui[i] = scanner.nextLong();
        }
        for (int i = 0; i < N; i++) {
            long strength = 0;
            for (int mask = 0; mask < (1 << N); mask++) {
                long sum = 0;
                for (int j = 0; j < N; j++) {
                    if ((mask & (1 << j)) && j != i && Ai[i] >= Li[j] && Ai[i] <= Ui[j]) {
                        sum += Si[j];
                    }
                }
                if (sum > 0) {
                    strength = (strength + calculateFib(sum + 1)) % (MOD + 3);
                }
            }
            System.out.print(strength + " ");
        }
    }
}

